(91, 1, '2022-09-27 13:12:06', '2022-09-27 13:12:06', '<!-- wp:heading {"textAlign":"center","level":1} -->\n<h1 class="has-text-align-center">Pressure</h1>\n<!-- /wp:heading -->\n\n<!-- wp:heading {"textAlign":"center"} -->\n<h2 class="has-text-align-center">Classical Mechanics</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pressure is defined as force per surface area, in SI units Newton per square Meter. </p>\n<!-- /wp:paragraph -->', 'Pressure (Mechanics)', '', 'publish', 'open', 'open', '', 'pressure-1', '', '', '2022-09-27 13:17:22', '2022-09-27 13:17:22', '', 0, 'https://taeko-and-co.ch/?p=91', 0, 'post', '', 0),
