>\n<!-- /wp:image -->\n\n<!-- wp:image {"id":160,"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image size-large"><img src="https://taeko-and-co.ch/wp-content/uploads/2022/09/august2020-1024x657.png" alt="" class="wp-image-160"/><figcaption>~August 2020 - Seedmap also used here</figcaption></figure>\n<!-- /wp:image -->\n\n<!-- wp:image -->\n<figure class="wp-block-image"><img/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->', 'Historic Taeko & Co Maps', '', 'inherit', 'closed', 'closed', '', '155-revision-v1', '', '', '2022-09-28 12:56:57', '2022-09-28 10:56:57', '', 155, 'https://taeko-and-co.ch/?p=162', 0, 'revision', '', 0),
