(209, 1, '2022-10-02 09:49:18', '2022-10-02 07:49:18', '<!-- wp:heading {"textAlign":"center","level":1} -->\n<h1 class="has-text-align-center">Signalization on Attecan Roads</h1>\n<!-- /wp:heading -->\n\n<!-- wp:heading -->\n<h2>Preword</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>The purpose of road signalization is to guarantee easy and correct usage of roadways. A well designed system is easy to understand and to learn. Atteca\'s road signage has undergone many updates since roads were first introduced in October of 2020. Now, as boats are taking the promentent role in short to medium distance travel, good signage is more important than ever. For this reason, Lprd245 &amp; I are reforming the signage, based on the early 2022 reform.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2>Basic Information</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>The typeface used for all signs is the SNV (Schweizerische Normenverein) font. It features concise, modern and ledgible characters.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>For signs where only numbers are displayed, a modified &amp; custom version of the Swiss Licence Plate font is used. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2>Colors</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Colors are important in aiding the readablity of signs. Atteca adapts these 3 general, base color schemes:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image {"id":192,"width":620,"height":216,"sizeSlug":"full","linkDestination":"none"} -->\n<figure class="wp-block-image size-full is-resized"><img src="https://taeko-and-co.ch/wp-content/uploads/2022/10/Artboard-1.png" alt="" class="wp-image-192" width="620" height="216"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p>Side Roads &amp; General Signage : #fff, #000, #000</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"style":{"color":{"background":"#33456a","text":"#ec9e3c"}}} -->\n<p class="has-text-color has-background" style="background-color:#33456a;color:#ec9e3c">Main Roads : #33456A, #fff, #EC9E3C</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"style":{"color":{"background":"#0f3d21","text":"#ec9e3c"}}} -->\n<p class="has-text-color has-background" style="background-color:#0f3d21;color:#ec9e3c">Expressways : #0F3D21, #fff, #EC9E3C</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2>Directional Signs</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>An overview of directional signs in the following table.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:table {"hasFixedLayout":true,"align":"wide","className":"is-style-regular"} -->\n<figure class="wp-block-table alignwide is-style-regular"><table class="has-fixed-layout"><tbody><tr><td class="has-text-align-left" data-align="left"></td><td class="has-text-align-center" data-align="center">Side Roads</td><td class="has-text-align-center" data-align="center">Main Roads</td><td class="has-text-align-center" data-align="center">Expressways</td></tr><tr><td class="has-text-align-left" data-align="left">In/At Intersection</td><td class="has-text-align-center" data-align="center"><img class="wp-image-195" style="width: 200px;" src="http://taeko-and-co.ch/wp-content/uploads/2022/10/in_side.png" alt=""><br>see "color coding" section</td><td class="has-text-align-center" data-align="center"><img class="wp-image-196" style="width: 200px;" src="http://taeko-and-co.ch/wp-content/uploads/2022/10/in_main.png" alt=""><br>Standard intersection<br><img class="wp-image-197" style="width: 200px;" src="http://taeko-and-co.ch/wp-content/uploads/2022/10/in_main_2.png" alt=""><br>Level seperated intersections</td><td class="has-text-align-center" data-align="center"><img class="wp-image-199" style="width: 200px;" src="http://taeko-and-co.ch/wp-content/uploads/2022/10/in_atb.png" alt=""><br>Splitting of Expressways<br><img class="wp-image-197" style="width: 200px;" src="http://taeko-and-co.ch/wp-content/uploads/2022/10/in_main_2.png" alt=""><br>Expressway Exit</td></tr><tr><td class="has-text-align-left" data-align="left">Before Intersection</td><td class="has-text-align-center" data-align="center"><img class="wp-image-202" style="width: 200px;" src="http://taeko-and-co.ch/wp-content/uploads/2022/10/bef_side.png" alt=""><br>Variant 1<br><img class="wp-image-203" style="width: 200px;" src="http://taeko-and-co.ch/wp-content/uploads/2022/10/bef_side1.png" alt=""><br>Variant 2</td><td class="has-text-align-center" data-align="center"><img class="wp-image-206" style="width: 200px;" src="http://taeko-and-co.ch/wp-content/uploads/2022/10/bef_main1.png" alt=""><br>Variant 1<br><img class="wp-image-205" style="width: 200px;" src="http://taeko-and-co.ch/wp-content/uploads/2022/10/bef_main.png" alt=""><br>Variant 2</td><td class="has-text-align-center" data-align="center"><img class="wp-image-207" style="width: 200px;" src="http://taeko-and-co.ch/wp-content/uploads/2022/10/atb_einspuren.png" alt=""><br>Splitting of Expressways<br><img class="wp-image-208" style="width: 200px;" src="http://taeko-and-co.ch/wp-content/uploads/2022/10/atb_exit.png" alt=""><br>Expressway Exit</td></tr><tr><td class="has-text-align-left" data-align="left">Intersection Announcement</td><td class="has-text-align-center" data-align="center"></td><td class="has-text-align-center" data-align="center"></td><td class="has-text-align-center" data-align="center"></td></tr><tr><td class="has-text-align-left" data-align="left">Distance Tables</td><td class="has-text-align-center" data-align="center"></td><td class="has-text-align-center" data-align="center"></td><td class="has-text-align-center" data-align="center"></td></tr></tbody></table></figure>\n<!-- /wp:table -->', 'Signalization on Attecan Roads', '', 'inherit', 'closed', 'closed', '', '188-revision-v1', '', '', '2022-10-02 09:49:18', '2022-10-02 07:49:18', '', 188, 'https://taeko-and-co.ch/?p=209', 0, 'revision', '', 0),
