(333, 1, '2022-12-28 21:00:31', '2022-12-28 20:00:31', '<!-- wp:heading {"level":1} -->\n<h1>Mod Downloads for the T&amp;C Minecraft Server (1.19.2)</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Taeko &amp; Co relies on a a variety of mods to work as it does. Some mods, although not many, are required by the client. Most of these mods are simply extras, which for many of T&amp;C\'s members are essential.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Ensure you have the latest version of the Fabric Mod Loader for <strong>1.19.2</strong> installed: <a href="https://fabricmc.net/use" target="_blank" rel="noreferrer noopener">https://fabricmc.net/use</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2>Essentials</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>The following mods are required to use the server. While it may be possible to join without them, large parts of the server will not work at all or not as expected. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>Create 0.5</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>T&amp;C Seasons Mod</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Fabric API</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:file {"id":329,"href":"https://taeko-and-co.ch/wp-content/uploads/2022/12/essentials.zip"} -->\n<div class="wp-block-file"><a id="wp-block-file--media-38ae9748-63f4-4935-9189-2d303d6014f6" href="https://taeko-and-co.ch/wp-content/uploads/2022/12/essentials.zip">essentials</a><a href="https://taeko-and-co.ch/wp-content/uploads/2022/12/essentials.zip" class="wp-block-file__button wp-element-button" download aria-describedby="wp-block-file--media-38ae9748-63f4-4935-9189-2d303d6014f6">Download</a></div>\n<!-- /wp:file -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2>Quality of Life</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>These mods generally enhance the experience of playing the game.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>Modmenu</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Litematica</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>MiniHUD</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Tweakeroo</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Malilib (Libraries)</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>WorldEdit (for the creative server)</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:file {"id":330,"href":"https://taeko-and-co.ch/wp-content/uploads/2022/12/quality-of-life.zip"} -->\n<div class="wp-block-file"><a id="wp-block-file--media-a8d9fdcc-7981-42d7-9143-06bafa7eac42" href="https://taeko-and-co.ch/wp-content/uploads/2022/12/quality-of-life.zip">quality-of-life</a><a href="https://taeko-and-co.ch/wp-content/uploads/2022/12/quality-of-life.zip" class="wp-block-file__button wp-element-button" download aria-describedby="wp-block-file--media-a8d9fdcc-7981-42d7-9143-06bafa7eac42">Download</a></div>\n<!-- /wp:file -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2>Performance</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>These mods significantly boost performance, especially on slower computers. Don\'t skip these!</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>Sodium</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Phosphor</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Indium </li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Spark (profiler)</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:file {"id":331,"href":"https://taeko-and-co.ch/wp-content/uploads/2022/12/performance.zip"} -->\n<div class="wp-block-file"><a id="wp-block-file--media-5513bd51-e156-46bf-b492-bcd91789d426" href="https://taeko-and-co.ch/wp-content/uploads/2022/12/performance.zip">performance</a><a href="https://taeko-and-co.ch/wp-content/uploads/2022/12/performance.zip" class="wp-block-file__button wp-element-button" download aria-describedby="wp-block-file--media-5513bd51-e156-46bf-b492-bcd91789d426">Download</a></div>\n<!-- /wp:file -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2>Necessary Extras</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>These mods make Taeko &amp; Co (specifically) much better.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul><!-- wp:list-item -->\n<li>TCBoatTweaker Ultra</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Xaero\'s Minimap</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Xaero\'s Worldmap</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:file {"id":332,"href":"https://taeko-and-co.ch/wp-content/uploads/2022/12/necessary-extras.zip"} -->\n<div class="wp-block-file"><a id="wp-block-file--media-8ea9b3d8-ff40-4f37-b6ce-faa94da8fe9d" href="https://taeko-and-co.ch/wp-content/uploads/2022/12/necessary-extras.zip">necessary-extras</a><a href="https://taeko-and-co.ch/wp-content/uploads/2022/12/necessary-extras.zip" class="wp-block-file__button wp-element-button" download aria-describedby="wp-block-file--media-8ea9b3d8-ff40-4f37-b6ce-faa94da8fe9d">Download</a></div>\n<!-- /wp:file -->', 'Mod Downloads', '', 'inherit', 'closed', 'closed', '', '328-revision-v1', '', '', '2022-12-28 21:00:31', '2022-12-28 20:00:31', '', 328, 'https://taeko-and-co.ch/?p=333', 0, 'revision', '', 0),
(342, 1, '2023-05-30 08:56:36', '2023-05-30 06:56:36', '', 'image', '', 'inherit', 'open', 'closed', '', 'image', '', '', '2023-05-30 08:56:36', '2023-05-30 06:56:36', '', 21, 'http://taeko-and-co.ch/wp-content/uploads/2023/05/image.png', 0, 'attachment', 'image/png', 0),
(343, 1, '2023-05-30 08:58:02', '2023-05-30 06:58:02', '<!-- wp:heading {"textAlign":"center","level":1} -->\n<h1 class="wp-block-heading has-text-align-center">A diversely disciplined creative collective.</h1>\n<!-- /wp:heading -->\n\n<!-- wp:search {"label":"","placeholder":"Seach Taeko \\u0026 Co...","buttonText":"Search"} /-->\n\n<!-- wp:image {"align":"wide","id":265,"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image alignwide size-large"><img src="http://taeko-and-co.ch/wp-content/uploads/2022/10/4-1024x551.png" alt="" class="wp-image-265"/><figcaption class="wp-element-caption">An old, ca. early 2021 birds eye view of Machinaka, Atami</figcaption></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p>Since 2020, the Taeko &amp; Co. Creative Collective has been an outlet for its<br>members to exercise their manifold forms of creative expression and<br>hobbies, be it posters, logos, architecture, or even urban planning. We<br>can do all this through the medium of our Minecraft server; the beginning<br>of our project. Here, three countries spearhead server development:<br>Atteca, Lyria, and Swarovski. These countries each contain their own<br>architecture, industry, and culture. We boast a serverwide network of<br>roads, and soon train lines.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><br>We would love to help you with your next project with our plethora of<br>skills. For business inquiries, please visit the commisions page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class="wp-block-heading">Quick Links</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="http://server.taeko-and-co.ch:8100">Server Map - Dynmap</a></p>\n<!-- /wp:paragraph -->', 'Home', '', 'inherit', 'closed', 'closed', '', '21-revision-v1', '', '', '2023-05-30 08:58:02', '2023-05-30 06:58:02', '', 21, 'https://taeko-and-co.ch/?p=343', 0, 'revision', '', 0),
(344, 1, '2023-05-30 09:04:11', '2023-05-30 07:04:11', '<!-- wp:heading {"textAlign":"center","level":1} -->\n<h1 class="wp-block-heading has-text-align-center">A diversely disciplined creative collective.</h1>\n<!-- /wp:heading -->\n\n<!-- wp:search {"label":"","placeholder":"Seach Taeko \\u0026 Co...","buttonText":"Search"} /-->\n\n<!-- wp:image {"align":"wide","id":265,"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image alignwide size-large"><img src="http://taeko-and-co.ch/wp-content/uploads/2022/10/4-1024x551.png" alt="" class="wp-image-265"/><figcaption class="wp-element-caption">An old, ca. early 2021 birds eye view of Machinaka, Atami</figcaption></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p>Since 2020, the Taeko &amp; Co. Creative Collective has been an outlet for its<br>members to exercise their manifold forms of creative expression and<br>hobbies, be it posters, logos, architecture, or even urban planning. We<br>can do all this through the medium of our Minecraft server; the beginning<br>of our project. Here, three countries spearhead server development:<br>Atteca, Lyria, and Swarovski. These countries each contain their own<br>architecture, industry, and culture. We boast a serverwide network of<br>roads train lines.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><br>We would love to help you with your next project with our plethora of<br>skills. For business inquiries, please visit the commisions page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class="wp-block-heading">Quick Links</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="http://server.taeko-and-co.ch:8100">Server Map - Dynmap</a></p>\n<!-- /wp:paragraph -->', 'Home', '', 'inherit', 'closed', 'closed', '', '21-revision-v1', '', '', '2023-05-30 09:04:11', '2023-05-30 07:04:11', '', 21, 'https://taeko-and-co.ch/?p=344', 0, 'revision', '', 0),
(346, 1, '2023-05-30 09:07:46', '2023-05-30 07:07:46', '', 'Commissions', '', 'publish', 'closed', 'closed', '', 'commissions', '', '', '2023-05-30 09:07:46', '2023-05-30 07:07:46', '', 0, 'https://taeko-and-co.ch/?page_id=346', 0, 'page', '', 0),
(347, 1, '2023-05-30 09:07:46', '2023-05-30 07:07:46', '<!-- wp:heading {"textAlign":"center","level":1} -->\n<h1 class="wp-block-heading has-text-align-center">Good design resonates with us...</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Design is, and always has been, at the forefront of everything we do. We believe that good, beautiful design comes hand in hand with flawless functionality, especially in the age of increasingly complex and frustratingly buggy software that is supposed to make our lives easier.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Taeko &amp; Co. stands for meaningful, subtle, accessible and functional design. We see the beauty in towering concrete infrastructure, sleek glass high rises, modern expressive buildings, state-of-the-art tunnels and concise signage. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If you see beauty in those examples too, consider looking through our portfolio to get inspired, or maybe even contacting us about potential commissions. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class="wp-block-heading">Portfolio</h2>\n<!-- /wp:heading -->\n\n<!-- wp:image {"id":317,"sizeSlug":"full","linkDestination":"none"} -->\n<figure class="wp-block-image size-full"><img src="http://taeko-and-co.ch/wp-content/uploads/2022/12/tc_logo.png" alt="" class="wp-image-317"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p><strong>The Taeko &amp; Co. Logo</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Our logo of course takes the first place in our portfolio. It is a proud collaboration between members of T&amp;C and pays homage to previous logos. The heavy typeface and waviness express our identity as a free, independent design collective. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:image {"id":391,"sizeSlug":"full","linkDestination":"none"} -->\n<figure class="wp-block-image size-full"><img src="https://taeko-and-co.ch/wp-content/uploads/2023/05/discordlogotc.png" alt="" class="wp-image-391"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p><strong>Icon of T&amp;C Logo</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:image {"id":392,"sizeSlug":"full","linkDestination":"none"} -->\n<figure class="wp-block-image size-full"><img src="https://taeko-and-co.ch/wp-content/uploads/2023/05/chaffeur_psd_en.png" alt="" class="wp-image-392"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p><strong>Chauffeur Transpassodome, </strong>poster for the Passodome ANR line on server</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:image {"id":394,"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image size-large"><img src="https://taeko-and-co.ch/wp-content/uploads/2023/05/Screenshot-2023-05-30-at-13.45.50-1024x762.png" alt="" class="wp-image-394"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p><strong>Road signs for Atteca &amp; Swarovski</strong>, see <a href="https://taeko-and-co.ch/index.php/2022/10/02/signalization-on-attecan-roads/" data-type="post" data-id="188">detailed development analysis</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:image {"id":395,"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image size-large"><img src="https://taeko-and-co.ch/wp-content/uploads/2023/05/milchbuck-1024x724.png" alt="" class="wp-image-395"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p><strong>Poster for Milchbuck Tunnel in Zurich</strong>, including colorized image from ETH Archives</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:image {"id":402,"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image size-large"><img src="https://taeko-and-co.ch/wp-content/uploads/2023/05/Screenshot-2023-05-30-at-14.10.16-1024x485.png" alt="" class="wp-image-402"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p><strong>Attecan National Railways</strong>, branding/logo</p>\n<!-- /wp:paragraph -->', 'Design', '', 'publish', 'closed', 'closed', '', 'design', '', '', '2023-05-30 14:11:06', '2023-05-30 12:11:06', '', 0, 'https://taeko-and-co.ch/?page_id=347', 0, 'page', '', 0),
