(386, 1, '2023-05-30 11:05:53', '2023-05-30 09:05:53', '<!-- wp:heading {"textAlign":"center","level":1} -->\n<h1 class="wp-block-heading has-text-align-center">A diversely disciplined creative collective.</h1>\n<!-- /wp:heading -->\n\n<!-- wp:search {"label":"","placeholder":"Seach Taeko \\u0026 Co...","buttonText":"Search"} /-->\n\n<!-- wp:image {"align":"wide","id":384,"sizeSlug":"large","linkDestination":"none"} -->\n<figure class="wp-block-image alignwide size-large"><img src="http://taeko-and-co.ch/wp-content/uploads/2023/05/2023-04-01_14.47.20-1024x548.png" alt="" class="wp-image-384"/><figcaption class="wp-element-caption">The northern entrance to the Tannen Tunnel, in Neutannen (Wengen), Atteca</figcaption></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p>Since 2020, the Taeko &amp; Co. Creative Collective has been an outlet for its<br>members to exercise their manifold forms of creative expression and<br>hobbies, be it posters, logos, architecture, or even urban planning. We<br>can do all this through the medium of our Minecraft server; the beginning<br>of our project. Here, three countries spearhead server development:<br>Atteca, Lyria, and Swarovski. These countries each contain their own<br>architecture, industry, and culture. We boast a serverwide network of<br>roads and railway lines.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><br>We would love to help you with your next project with our plethora of<br>skills. For business inquiries, please visit the commisions page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class="wp-block-heading">Quick Links</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href="http://server.taeko-and-co.ch:8100">Server Map - Dynmap</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class="wp-block-heading">Latest Posts</h2>\n<!-- /wp:heading -->\n\n<!-- wp:query {"queryId":19,"query":{"perPage":3,"pages":0,"offset":0,"postType":"post","order":"desc","orderBy":"date","author":"","search":"","exclude":[],"sticky":"","inherit":false},"displayLayout":{"type":"list","columns":3}} -->\n<div class="wp-block-query"><!-- wp:post-template -->\n<!-- wp:post-title {"isLink":true} /-->\n\n<!-- wp:post-featured-image {"isLink":true,"align":"wide"} /-->\n\n<!-- wp:post-excerpt /-->\n\n<!-- wp:separator {"opacity":"css"} -->\n<hr class="wp-block-separator has-css-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:post-date /-->\n<!-- /wp:post-template --></div>\n<!-- /wp:query -->', 'Home', '', 'inherit', 'closed', 'closed', '', '21-revision-v1', '', '', '2023-05-30 11:05:53', '2023-05-30 09:05:53', '', 21, 'https://taeko-and-co.ch/?p=386', 0, 'revision', '', 0),
(389, 1, '2023-05-30 11:25:55', '2023-05-30 09:25:55', '<!-- wp:heading -->\n<h2 class="wp-block-heading">Good design resonates with us...</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Design is, and always has been, at the forefront of everything we do. We believe that good, beautiful design comes hand in hand with flawless functionality, especially in the age of increasingly complex and frustratingly buggy software that is supposed to make our lives easier.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Taeko &amp; Co. stands for meaningful, subtle, accessible and functional design. We see the beauty in towering concrete infrastructure, sleek glass high rises, modern expressive buildings, state-of-the-art tunnels and concise signage. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If you see beauty in those examples too, consider looking through our portfolio to get inspired, or maybe even contacting us about potential commissions. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class="wp-block-heading">Portfolio (coming soon)</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>...</p>\n<!-- /wp:paragraph -->', 'Design', '', 'inherit', 'closed', 'closed', '', '347-revision-v1', '', '', '2023-05-30 11:25:55', '2023-05-30 09:25:55', '', 347, 'https://taeko-and-co.ch/?p=389', 0, 'revision', '', 0),
