(457, 1, '2025-03-18 15:53:21', '2025-03-18 14:53:21', '<!-- wp:heading {"textAlign":"center","level":1} -->\n<h1 class="wp-block-heading has-text-align-center">A diversely disciplined creative collective.</h1>\n<!-- /wp:heading -->\n\n<!-- wp:search {"label":"","placeholder":"Search Taeko \\u0026 Co...","buttonText":"Search"} /-->\n\n<!-- wp:heading {"textAlign":"center"} -->\n<h2 class="wp-block-heading has-text-align-center"><strong>Download 1.20.1 Mods</strong></h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {"align":"center"} -->\n<p class="has-text-align-center">Make sure you have Prism/MultiMC (or any of its forks) installed. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {"align":"center"} -->\n<p class="has-text-align-center">This download contains only the mods required to join the server. We recommend installing a performance mod like Sodium, Distant Horizons and the MaLiLib library mods Tweakeroo and MiniHUD to get the best experience possible. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:file {"id":454,"href":"https://taeko-and-co.ch/wp-content/uploads/2025/03/TCBaseMods.zip","align":"center"} -->\n<div class="wp-block-file aligncenter"><a>TCBaseMods.zip</a><a href="https://taeko-and-co.ch/wp-content/uploads/2025/03/TCBaseMods.zip" class="wp-block-file__button wp-element-button" download>Prism/MultiMC Instance 1.20.1 - Download</a></div>\n<!-- /wp:file -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:columns -->\n<div class="wp-block-columns"><!-- wp:column -->\n<div class="wp-block-column"><!-- wp:paragraph -->\n<p><em><strong>Since 2020</strong></em>, the Taeko &amp; Co. Creative Collective has been an outlet for its members to exercise their manifold forms of creative expression and hobbies, be it posters, logos, architecture, or even urban planning. We can do all this through the medium of our Minecraft server; the beginning<br>of our project. Here, three countries spearhead server development:<br><strong>Atteca, Lyria, and Swarovski</strong>. These countries each contain their own architecture, industry, and culture. We boast a serverwide network of roads and railway lines.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>We hope to see you in our Discord or on the server soon!</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class="wp-block-column"><!-- wp:html -->\n<center><iframe src="https://discord.com/widget?id=1118461204281696258&theme=dark" width="350" height="500" allowtransparency="true" frameborder="0" sandbox="allow-popups allow-popups-to-escape-sandbox allow-same-origin allow-scripts"></iframe></center>\n<!-- /wp:html --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:separator -->\n<hr class="wp-block-separator has-alpha-channel-opacity"/>\n<!-- /wp:separator -->\n\n<!-- wp:paragraph -->\n<p>We would love to help you with your next project with our plethora of<br>skills. For business inquiries, please visit the commisions page.</p>\n<!-- /wp:paragraph -->', 'Home', '', 'inherit', 'closed', 'closed', '', '21-revision-v1', '', '', '2025-03-18 15:53:21', '2025-03-18 14:53:21', '', 21, 'https://taeko-and-co.ch/?p=457', 0, 'revision', '', 0),
